mapper.select:

SELECT COUNT(*)
FROM
     MSP_REQUEST@DL_MSP A
    ,MSP_REQUEST_CSTMR@DL_MSP B
    ,MSP_REQUEST_STATE@DL_MSP C
WHERE
    B.CSTMR_NAME = #{cstmrName}
    AND B.CSTMR_MOBILE_FN = #{cstmrMobileFn}
    AND B.CSTMR_MOBILE_MN = #{cstmrMobileMn}
    AND B.CSTMR_MOBILE_RN = #{cstmrMobileRn}
    AND A.REQUEST_KEY = B.REQUEST_KEY
    AND B.REQUEST_KEY = C.REQUEST_KEY

mapper.insert:
SELECT SMS_SEQ.NEXTVAL@DL_MSP FROM DUAL
INSERT INTO MSG_QUEUE@DL_MSP ( MSEQ,
SUBJECT ,
MSG_TYPE, DSTADDR, CALLBACK, STAT, TEXT, EXPIRETIME, REQUEST_TIME, OPT_ID
,FILECNT, FILECNT_CHECKUP, FILELOC1, FILESIZE1
) VALUES ( #{SMS_SEQ, jdbcType=NUMERIC},
#{I_SUBJECT},
#{I_MSG_TYPE}, #{I_CTN}, #{I_CALLBACK}, 0, #{I_MSG}, 7200, SYSDATE, 'MCP'
,#{I_FILECNT}, #{I_FILECNT_CHECKUP}, #{I_FILELOC1}, #{I_FILESIZE1}
)
